import './App.css'

export function scrollElement(elementId) {
    const scrollToView = () => {
      setTimeout(() => {
        const element = document.querySelector(`${elementId}`);
        console.log(`${elementId}`);
        element.scrollIntoView({ behavior: "smooth" });
      }, 100); // adjust the delay as needed
    };
    return scrollToView;
  }
